INSERT OR REPLACE INTO cms_stories (id,title,slug,excerpt,status,category,author,hero_image,tags,blocks_json,created_at,updated_at,published_at) VALUES (
      'story-semiconductor-pli',
      'Semiconductor PLI Expansion: What It Means for India''s Tech Ambitions',
      'semiconductor-pli-expansion',
      'The Cabinet has approved a ₹1.2 lakh crore expansion of the Production Linked Incentive scheme for semiconductor manufacturing. Here''s what changes and why it matters.',
      'published',
      'economy',
      'The Breakdown Editorial',
      '/images/stories/semiconductor-pli.jpg',
      '[]',
      '[{"id":"blk-1","type":"hero","data":{"headline":"Semiconductor PLI Expansion: What It Means for India''s Tech Ambitions","summary":"The Cabinet has approved a ₹1.2 lakh crore expansion of the Production Linked Incentive scheme for semiconductor manufacturing. Here''s what changes and why it matters.","heroImage":"/images/stories/semiconductor-pli.jpg","category":"economy","author":"The Breakdown Editorial","publishedAt":"2026-07-02T09:30:00Z"},"collapsed":false},{"id":"blk-2","type":"text","data":{"html":"<p>The Cabinet Committee on Economic Affairs (CCEA) on Thursday approved a ₹1.2 lakh crore expansion of the Production Linked Incentive (PLI) scheme for semiconductor manufacturing, marking one of the largest single-sector incentives in India''s industrial policy history.</p><p>The expanded scheme covers chip design, fabrication, assembly, testing, and packaging — creating an end-to-end semiconductor ecosystem for the first time.</p>"},"collapsed":false},{"id":"blk-3","type":"timeline","data":{"events":[{"date":"Dec 2021","title":"PLI for Semiconductor Announced","description":"Union Cabinet approved ₹76,000 crore PLI for semiconductor and display manufacturing."},{"date":"Sep 2022","title":"First Applications Received","description":"Government received 5 applications for chip fabrication units under the scheme."},{"date":"Jun 2024","title":"Vedanta-Foxconn JV Collapses","description":"The Vedanta-Foxconn joint venture for a Gujarat fab was dissolved."},{"date":"Mar 2025","title":"Revised Scheme Drafted","description":"MeitY drafted an expanded version after industry feedback on the original scheme."},{"date":"Jul 2026","title":"₹1.2 Lakh Crore Expansion Approved","description":"CCEA approved the expanded PLI scheme covering the full semiconductor value chain."}]},"collapsed":false},{"id":"blk-4","type":"evidence","data":{"claim":"India''s semiconductor market is projected to reach $100 billion by 2030.","data":"Current market size: $38 billion (2025). Projected: $100 billion (2030). CAGR: 21.4%.","source":"India Semiconductor Market Report 2026","sourceUrl":"https://example.com/semiconductor-report","tier":2},"collapsed":false},{"id":"blk-5","type":"chart","data":{"chartType":"bar","title":"Global Semiconductor Manufacturing Capacity by Country (2026)","data":[{"label":"Taiwan","value":48},{"label":"South Korea","value":22},{"label":"Japan","value":12},{"label":"China","value":8},{"label":"USA","value":6},{"label":"India","value":1},{"label":"Others","value":3}],"caption":"Source: Semiconductor Industry Association"},"collapsed":false},{"id":"blk-6","type":"faq","data":{"items":[{"question":"What is the total outlay of the expanded PLI scheme?","answer":"The expanded scheme has an outlay of ₹1.2 lakh crore over 6 years, up from the original ₹76,000 crore."},{"question":"Which companies are expected to benefit?","answer":"The scheme is open to both domestic and international semiconductor companies. Key players include Tata Electronics, US-based chipmakers, and several fabless design startups."},{"question":"How many jobs will this create?","answer":"The government estimates the scheme will create 85,000 direct jobs and 2.5 lakh indirect jobs in the semiconductor ecosystem."}]},"collapsed":false},{"id":"blk-7","type":"sources","data":{"sources":[{"title":"PIB Release: Cabinet Approves Semiconductor PLI Expansion","url":"https://pib.gov.in/ReleaseDetail.aspx?relid=12345","accessedAt":"2026-07-02","tier":1},{"title":"MeitY Semiconductor Policy Document","url":"https://meity.gov.in/semiconductor-policy","accessedAt":"2026-07-01","tier":1},{"title":"SIA Global Semiconductor Report 2026","url":"https://semiconductors.org/report-2026","accessedAt":"2026-06-30","tier":2}]},"collapsed":false}]',
      '2026-07-02T06:00:00Z',
      '2026-07-02T09:30:00Z',
      '2026-07-02T09:30:00Z'
    );
INSERT OR REPLACE INTO cms_stories (id,title,slug,excerpt,status,category,author,hero_image,tags,blocks_json,created_at,updated_at,published_at) VALUES (
      'story-dpdp-bill',
      'DPDP Amendment Bill: What Changes After Lok Sabha Passage',
      'dpdp-amendment-bill-loksabha',
      'The Digital Personal Data Protection (Amendment) Bill, 2026 was passed in Lok Sabha with 3 key amendments. Here''s a complete breakdown.',
      'published',
      'policy',
      'The Breakdown Editorial',
      '/images/stories/dpdp-bill.jpg',
      '[]',
      '[{"id":"blk-8","type":"hero","data":{"headline":"DPDP Amendment Bill: What Changes After Lok Sabha Passage","summary":"The Digital Personal Data Protection (Amendment) Bill, 2026 was passed in Lok Sabha with 3 key amendments. Here''s a complete breakdown.","heroImage":"/images/stories/dpdp-bill.jpg","category":"policy","author":"The Breakdown Editorial","publishedAt":"2026-07-02T08:15:00Z"},"collapsed":false},{"id":"blk-9","type":"quote","data":{"text":"This bill balances the need for data protection with the requirements of innovation and economic growth.","speaker":"Minister of Electronics and IT","context":"In response to debate on the DPDP Amendment Bill in Lok Sabha"},"collapsed":false},{"id":"blk-10","type":"text","data":{"html":"<p>The Digital Personal Data Protection (Amendment) Bill, 2026 was passed in the Lok Sabha on Wednesday with three key amendments. The bill now moves to the Rajya Sabha for consideration.</p><p>The amendments address concerns raised by the Joint Parliamentary Committee and civil society organizations regarding data localization, consent frameworks, and penalties for non-compliance.</p>"},"collapsed":false},{"id":"blk-11","type":"evidence","data":{"claim":"Over 80% of Indian companies will need to revise their data handling practices.","data":"Estimated compliance cost impact: ₹5-15 crore per large enterprise. Timeline: 12 months from enactment.","source":"Industry Association Impact Assessment","sourceUrl":"","tier":3},"collapsed":false},{"id":"blk-12","type":"sources","data":{"sources":[{"title":"Lok Sabha Debate Transcript, July 1 2026","url":"https://sansad.in/ls/debate","accessedAt":"2026-07-02","tier":1},{"title":"DPDP Bill 2026 - Full Text","url":"https://egazette.gov.in/dpdp-2026","accessedAt":"2026-07-01","tier":1}]},"collapsed":false}]',
      '2026-07-01T14:00:00Z',
      '2026-07-02T08:15:00Z',
      '2026-07-02T08:15:00Z'
    );
INSERT OR REPLACE INTO cms_stories (id,title,slug,excerpt,status,category,author,hero_image,tags,blocks_json,created_at,updated_at,published_at) VALUES (
      'story-rbi-repo-rate',
      'Explained: How RBI''s Repo Rate Decision Affects Your Loan EMIs',
      'rbi-repo-rate-loan-emi-impact',
      'RBI held the repo rate at 6.50% with a 5:1 MPC vote. What this means for borrowers, savers, and the economy.',
      'draft',
      'economy',
      'The Breakdown Editorial',
      '',
      '[]',
      '[{"id":"blk-13","type":"hero","data":{"headline":"Explained: How RBI''s Repo Rate Decision Affects Your Loan EMIs","summary":"RBI held the repo rate at 6.50% with a 5:1 MPC vote. What this means for borrowers, savers, and the economy.","heroImage":"","category":"economy","author":"The Breakdown Editorial","publishedAt":""},"collapsed":false},{"id":"blk-14","type":"text","data":{"html":"<p>The Reserve Bank of India''s Monetary Policy Committee (MPC) voted 5:1 to keep the repo rate unchanged at 6.50% for the 8th consecutive meeting. The decision was widely expected by markets...</p>"},"collapsed":true},{"id":"blk-15","type":"statistics","data":{"stats":[{"value":"6.50%","label":"Repo Rate","change":"unchanged","direction":"up"},{"value":"5:1","label":"MPC Vote","change":"","direction":"up"},{"value":"4.8%","label":"CPI Inflation","change":"-0.2pp","direction":"down"},{"value":"6.5%","label":"GDP Growth Forecast","change":"+0.1pp","direction":"up"}]},"collapsed":false}]',
      '2026-07-01T10:00:00Z',
      '2026-07-01T16:00:00Z',
      NULL
    );
INSERT OR REPLACE INTO cms_stories (id,title,slug,excerpt,status,category,author,hero_image,tags,blocks_json,created_at,updated_at,published_at) VALUES (
      'story-aadhaar-sc-review',
      'Supreme Court to Review Aadhaar Constitutional Validity',
      'supreme-court-aadhaar-review',
      'The Supreme Court has agreed to review the constitutional validity of Aadhaar, sending the case to a 5-judge constitution bench.',
      'review',
      'policy',
      'The Breakdown Editorial',
      '/images/stories/aadhaar-sc.jpg',
      '[]',
      '[{"id":"blk-16","type":"hero","data":{"headline":"Supreme Court to Review Aadhaar Constitutional Validity","summary":"The Supreme Court has agreed to review the constitutional validity of Aadhaar, sending the case to a 5-judge constitution bench.","heroImage":"/images/stories/aadhaar-sc.jpg","category":"policy","author":"The Breakdown Editorial","publishedAt":""},"collapsed":false},{"id":"blk-17","type":"timeline","data":{"events":[{"date":"Sep 2018","title":"Supreme Court Upholds Aadhaar","description":"5-judge bench upheld Aadhaar''s constitutional validity (4:1 majority)."},{"date":"Aug 2023","title":"Review Petition Filed","description":"Civil liberties organizations filed review petitions citing new privacy concerns."},{"date":"Jun 2026","title":"Supreme Court Admits Review","description":"SC agreed to hear review petitions, referring to 5-judge constitution bench."},{"date":"Jul 2026","title":"Hearing Scheduled","description":"Constitution bench hearing set for August 2026."}]},"collapsed":false},{"id":"blk-18","type":"callout","data":{"type":"warning","title":"What''s at Stake","text":"If the court overturns its 2018 judgment, over 1.3 billion Aadhaar enrollments and thousands of government services linked to Aadhaar could be affected. The judgment could redefine the scope of privacy rights under Article 21."},"collapsed":false}]',
      '2026-07-02T04:00:00Z',
      '2026-07-02T10:00:00Z',
      NULL
    );
