INSERT OR REPLACE INTO cms_fixes (id,title,slug,problem,root_causes,existing_solutions,global_examples,recommended_actions,citizen_actions,government_actions,metrics,status,created_at,updated_at) VALUES (
      'fix-19-mrs339h6',
      'Fixing PDS Leakage Through Digitization',
      'fix-ration-digitization',
      'India''s Public Distribution System (PDS) loses an estimated 40% of subsidized food grains to leakages — diversion to open market, ghost beneficiaries, and fake ration cards.',
      '["Manual record-keeping vulnerable to manipulation","Lack of biometric authentication at Fair Price Shops","No real-time inventory tracking from warehouse to shop","Political patronage in ration shop dealerships"]',
      '[{"title":"ePoS System","description":"Electronic Point of Sale devices installed at ration shops for biometric authentication."}]',
      '[{"country":"Brazil","approach":"Bolsa Familia conditional cash transfer with biometric ID","outcome":"Reduced leakage to under 5%"}]',
      '[{"action":"Mandate Aadhaar-based biometric authentication at all FPS","responsible":"Department of Food & Public Distribution","timeline":"6 months"}]',
      '["Check your ration entitlement online via the Anna Bhagya portal","Report FPS irregularities to the toll-free helpline 1967"]',
      '["Integrate PDS portal with Aadhaar for deduplication","Install GPS-enabled ePoS devices at all FPS"]',
      '[{"metric":"PDS Leakage Rate","currentValue":"40%","targetValue":"10%","source":"NIPFP Study 2025"}]',
      'published',
      '2026-05-25T08:00:00Z',
      '2026-05-25T08:00:00Z'
    );
